//帮别人调
#include <bits/stdc++.h>
using namespace std;
int main()
{
	int n,k;
	cin>>n>>k;
	int t=1,ans=0;
	for(int i=1;i<=n;i++)
	{
		t*=10;
	}
	for(int i=1;i<t;i++)
	{
		int sum=0,tmp=i;
		while(tmp)
		{
			sum+=tmp%10;
			tmp/=10;
		}
		if(sum<=k)
		{
			ans++;
		}
	}
	cout<<ans;
	return 0;
}
